+#[cfg(test)]
+mod tests {
+    use super::*;
+
+    #[test]
+    fn new_starts_calibrating() {
+        let c = LocalizationChooser::new(SafetyLevel::Strict);
+        assert_eq!(c.state(), ChooserState::Calibrating);
